SELECT 
FROM vso_approval t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.approval_id = #{approvalId}


    AND t.order_id = #{orderId}


    AND t.approval_type = #{approvalType}


    AND t.approval_status = #{approvalStatus}

ORDER BY t.id DESC

